-- GENERATED by @brain/semantic-metrics compiler — DO NOT EDIT. Change the YAML + recompile.
-- Tenancy: the BRAND_PREDICATE sentinel (below) is replaced with `brand_id = ?` by the serving seam.
CREATE OR REPLACE VIEW iceberg.brain_serving.mv_metric_cm1_pct_month AS
WITH base AS (
  SELECT
    brand_id,
    date_trunc('month', conversion_at) AS period,
    currency_code,
    channel,
    SUM(cm1_minor) AS cm1_minor,
    SUM(net_revenue_minor) AS net_revenue_minor
  FROM iceberg.brain_serving.semantic_order
  WHERE conversion_at IS NOT NULL
    AND ${BRAND_PREDICATE}
  GROUP BY 1, 2, 3, 4
)
SELECT
  brand_id,
  period,
  currency_code,
  channel,
  cm1_minor,
  net_revenue_minor,
  (CAST(cm1_minor AS double) / NULLIF(net_revenue_minor, 0)) AS cm1_pct
FROM base;
